import anthropic
import json

client = anthropic.Anthropic()

# Define tools for the agent
tools = [
    {
        "name": "search_database",
        "description": "Search the product database for items matching the query",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search terms"},
                "max_results": {"type": "integer", "default": 10}
            },
            "required": ["query"]
        }
    },
    {
        "name": "get_product_details",
        "description": "Get full details for a specific product by ID",
        "input_schema": {
            "type": "object",
            "properties": {
                "product_id": {"type": "string"}
            },
            "required": ["product_id"]
        }
    }
]

def run_agent_with_interleaved_thinking(user_query: str) -> str:
    messages = [{"role": "user", "content": user_query}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",      # Extended thinking requires Opus or Sonnet 3.7+
            max_tokens=16000,
            thinking={
                "type": "enabled",
                "budget_tokens": 8000     # Budget per thinking block, not total
            },
            tools=tools,
            messages=messages,
        )

        # Check for thinking blocks and tool use
        thinking_blocks = [b for b in response.content if b.type == "thinking"]
        tool_use_blocks = [b for b in response.content if b.type == "tool_use"]

        if thinking_blocks:
            print(f"[Thinking]: {thinking_blocks[0].thinking[:200]}...")  # Display first 200 chars

        if not tool_use_blocks:
            # No more tool calls — extract final text response
            text_blocks = [b for b in response.content if b.type == "text"]
            return text_blocks[0].text if text_blocks else ""

        # Execute tool calls and build tool_result messages
        tool_results = []
        for tool_use in tool_use_blocks:
            # Simulated tool execution — replace with real implementations
            if tool_use.name == "search_database":
                result = {"results": [{"id": "P001", "name": "Widget A", "price": 29.99}]}
            elif tool_use.name == "get_product_details":
                result = {"id": tool_use.input["product_id"], "description": "Full details here", "stock": 50}
            else:
                result = {"error": "Unknown tool"}

            tool_results.append({
                "type": "tool_result",
                "tool_use_id": tool_use.id,
                "content": json.dumps(result)
            })

        # Append assistant response and tool results, then loop
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

# Run the agent
result = run_agent_with_interleaved_thinking("Find products under $30 and check the stock for the cheapest one")
print(result)
